import React, { useState, useEffect } from 'react';

const ViewForm = (props) => {
    const initialFieldValues = {
        Pergunta: '',
        A: '',
        B: '',
        C: '',
        D: ''
    }

    var [values, setValues] = useState(initialFieldValues)


    useEffect(() => {
        if (props.currentId == '')
            setValues({ ...initialFieldValues })
        else
            setValues({
                ...props.contactObjects[props.currentId]
            })
    }, [props.currentId, props.contactObjects])

    const handleInputChange = e => {
        var { name, value } = e.target;
        setValues({
            ...values,
            [name]: value
        })
    }

    const handleFormSubmit = e => {
        e.preventDefault()
        props.addOrEdit(values);
    }

    return (
        
        
        <form autoComplete="off" onSubmit={handleFormSubmit}>





           
                          






                          <div className="form-group input-group">
                <div className="input-group-prepend">
                    <div className="input-group-text">
                        
                    </div>
                </div>
                <p className="py-3 px-6 text-left"><b>Pergunta Bônus:</b> {values.Pergunta}</p>
            </div>
            <div className="form-row">
                
                <div className="form-group input-group col-md-6">
                    <div className="input-group-prepend">
                        <div className="input-group-text">
                           
                        </div>
                    </div>
                    <p className="py-3 px-6 text-left"><b>Muito Satisfeito:</b> {values.A}<span className="py-3 px-6 text-left"><b>Valor:</b> {values.A_valor}</span></p>
                    
                </div>
                <div className="form-group input-group col-md-6">
                    <div className="input-group-prepend">
                        <div className="input-group-text">
                            
                        </div>
                    </div>
                    <p className="py-3 px-6 text-left"><b>Satisfeito:</b> {values.B}<span className="py-3 px-6 text-left"><b>Valor:</b> {values.B_valor}</span></p>
                </div>
                <div className="form-group input-group col-md-6">
                    <div className="input-group-prepend">
                        <div className="input-group-text">
                           
                        </div>
                    </div>
                    <p className="py-3 px-6 text-left"><b>Regular:</b> {values.C}<span className="py-3 px-6 text-left"><b>Valor:</b> {values.C_valor}</span></p>
                </div>
                <div className="form-group input-group col-md-6">
                    <div className="input-group-prepend">
                        <div className="input-group-text">
                            
                        </div>
                    </div>
                    <p className="py-3 px-6 text-left"><b>Insatisfeito:</b> {values.D}<span className="py-3 px-6 text-left"><b>Valor:</b> {values.D_valor}</span></p>
                </div>
            </div>








          








            
        </form>
    );
}

export default ViewForm;