import React, { useRef, useState, useEffect } from "react"
import { Form, Button, Card, Alert } from "react-bootstrap"
import { useAuth } from "./AuthContext"
import { Link, useHistory } from "react-router-dom"
import firebase from './firebase'

export default function Signup() {
  const usernameRef = useRef()
  const telefoneRef = useRef()
  const departamentoRef = useRef()
  const emailRef = useRef()
  const passwordRef = useRef()
  const passwordConfirmRef = useRef()
  const { currentUser, signup } = useAuth()
  const [error, setError] = useState("")
  const [loading, setLoading] = useState(false)
  const history = useHistory()

  async function handleSubmit(e) {
    e.preventDefault()

    if (passwordRef.current.value !== passwordConfirmRef.current.value) {
      return setError("Passwords do not match")
    }

    try {
      setError("")
      setLoading(true)
      await signup(emailRef.current.value, passwordRef.current.value)

      localStorage.setItem("firstlogin", "true");
      localStorage.setItem("username", usernameRef.current.value);
      localStorage.setItem("email", emailRef.current.value);
      localStorage.setItem("phone", telefoneRef.current.value);
      localStorage.setItem("departamento", departamentoRef.current.value);
      
      history.push("/")
    } catch {
      setError("Failed to create an account")
    }

 
    setLoading(false)
   
  }

  function cadastroRealtime(){
    
    //firebase.database().ref("users/"+currentUser.uid).child("Email").set(emailRef.current.value);
    //firebase.database().ref("users/"+currentUser.uid).child("NumberPhone").set(telefoneRef.current.value);
    //firebase.database().ref("users/"+currentUser.uid).child("username").set(usernameRef.current.value);
    //firebase.database().ref("users/"+currentUser.uid).child("Tags").set(departamentoRef.current.value);

   
  }


  return (
    <>
    <script>
    <link href="https://cdn.jsdelivr.net/npm/bootstrap@5.0.2/dist/css/bootstrap.min.css" rel="stylesheet" integrity="sha384-EVSTQN3/azprG1Anm3QDgpJLIm9Nao0Yz1ztcQTwFspd3yD65VohhpuuCOmLASjC" crossorigin="anonymous"/>
    </script>
      <Card>
        <Card.Body>
          <h2 className="text-center mb-4">Sign Up</h2>
          {error && <Alert variant="danger">{error}</Alert>}
          <Form onSubmit={handleSubmit}>
          <Form.Group id="email">
              <Form.Label>Username</Form.Label>
              <Form.Control type="username" ref={usernameRef} required />
            </Form.Group>
            <Form.Group id="email">
              <Form.Label>Email</Form.Label>
              <Form.Control type="email" ref={emailRef} required />
            </Form.Group>
            <Form.Group id="email">
              <Form.Label>Telefone</Form.Label>
              <Form.Control type="phone" ref={telefoneRef} required />
            </Form.Group>
            <Form.Group id="password">
              <Form.Label>Password</Form.Label>
              <Form.Control type="password" ref={passwordRef} required />
            </Form.Group>
            <Form.Group id="password-confirm">
              <Form.Label>Password Confirmation</Form.Label>
              <Form.Control type="password" ref={passwordConfirmRef} required />
            </Form.Group>
            <Form.Group id="email">
              <Form.Label>Departamento</Form.Label>
              <Form.Control id={departamentoRef} type="departamento" ref={departamentoRef} required />
            </Form.Group>
            <Button disabled={loading} className="w-100" type="submit" >
              Sign Up
            </Button>
          </Form>
        </Card.Body>
      </Card>
      <div className="w-100 text-center mt-2">
        Already have an account? <Link to="/login">Log In</Link>
      </div>
    </>
  )
}
